import React, { useState } from 'react';

function TradeForm(props) {
    const [trade, setTrade] = useState({
        id:0,
        stock:'MES',
        method:'Method',
        quantity:0,
        profitLoss:0
    })

    const handleStock = e => {
        setTrade({ stock: e.target.value })     
    }
    const handleMethod = e => {
        setTrade({ method: e.target.value })
    }
    const handleQuantity = e => {
        setTrade({ quantity: e.target.value })
    }
    const handleProfitLoss = e => {
        setTrade({ profitLoss: e.target.value })
    }

    const handleSubmit = e => {
        e.preventDefault()
        console.log(trade)
    }

    return(
        <form onSubmit={handleSubmit}>
            <span>Stock</span><span className='buffer'></span>
            <span>Method</span><span className='buffer'></span>
            <span>Quantity</span><span className='buffer'></span>
            <span>P/L</span><span className='buffer'></span>

            <p className='formLabel-buffer'></p>

            <select onChange={handleStock} autoFocus>
                <option>MES</option>
            </select>
            <select onChange={handleMethod}>
                <option>Bollinger</option>
                <option>--S & R--</option>
            </select >
            <input onChange={handleQuantity} type='number' defaultValue='1' min='1' step='1' />
            <input onChange={handleProfitLoss} type='number' step='0.25' />

            <button type='submit'>+Trade</button>
        </form>  
    )
}

export default TradeForm;
